sys_hub_input_scripts.script:
{"docintegratorinuse":{"scriptActive":true,"script":"/*
**Access Flow/Action data using the fd_data object. Script must return a value.
**example: var shortDesc = fd_data.trigger.current.short_description;
**return shortDesc;
*/
var DocIntegratorSettings = new x_153465_discovert.taskerDocumentScripts().isInstalled();
gs.debug('Create Suggested Task - Copy Document Folders - DocIntegrator Settings - DocIntegratorSettings.code: ' + DocIntegratorSettings.code);
return DocIntegratorSettings.code==1;"}}

